create table am_main.hwas_lebenszyklus (
    lz_id        number
        generated by default as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 start with 1 cache 20 noorder
        nocycle nokeep noscale
    not null enable,
    bezeichnung  varchar2(100 byte),
    beschreibung varchar2(400 byte),
    inserted     date,
    updated      date,
    inserted_by  varchar2(100 byte),
    updated_by   varchar2(100 byte)
)
no inmemory;

alter table am_main.hwas_lebenszyklus
    add constraint pk_lebenszyklus_id primary key ( lz_id )
        using index enable;

